const drawForSelectionMethod = drawMode === "multiple_without_replacement"
    ? `
  /**
   * Draw multiple candidates for selection (without replacement)
   * Tier-diversity-first: draw one from each distinct tier before weighted fallback.
   * Supports duplicatePolicy="forbid" to prevent duplicates.
   */
  drawForSelection(count: number = ${choiceCount}): T[] {
    if (this.items.length === 0) {
      print(\`[Rune Weaver] ${className}: No items in pool\`);
      return [];
    }

    const result: T[] = [];
    const drawnIds = new Set<string>();${hasSessionState ? `
    const availableItems = this.items.filter(item => 
      this.sessionState.remainingTalentIds.includes((item.item as any).id)
    );` : `
    const availableItems = [...this.items];`}

    if (availableItems.length === 0) {
      print(\`[Rune Weaver] ${className}: No available items in session pool\`);
      return [];
    }

    // Group available items by tier
    const tierGroups = new Map<number, WeightedItem<T>[]>();
    for (const item of availableItems) {
      const tier = item.tier ?? 0;
      if (!tierGroups.has(tier)) {
        tierGroups.set(tier, []);
      }
      tierGroups.get(tier)!.push(item);
    }

    const sortedTiers = Array.from(tierGroups.keys()).sort((a, b) => a - b);

    // Phase 1: Draw one candidate from each distinct tier (diversity-first)
    for (const tier of sortedTiers) {
      if (result.length >= count) break;

      const tierCandidates = tierGroups.get(tier)!.filter(item => {
        const itemId = (item.item as any).id;
        return !drawnIds.has(itemId);
      });

      if (tierCandidates.length === 0) continue;

      const tierTotalWeight = tierCandidates.reduce((sum, item) => sum + item.weight, 0);
      if (tierTotalWeight <= 0) continue;

      let random = RandomFloat(0, tierTotalWeight);
      let drawnItem: WeightedItem<T> | null = null;

      for (const item of tierCandidates) {
        random -= item.weight;
        if (random <= 0) {
          drawnItem = item;
          break;
        }
      }

      if (drawnItem) {
        const itemId = (drawnItem.item as any).id;
        result.push(drawnItem.item);
        drawnIds.add(itemId);

        // Remove from available items
        const index = availableItems.indexOf(drawnItem);
        if (index > -1) {
          availableItems.splice(index, 1);
        }
      }
    }

    // Phase 2: Weighted random fallback for remaining slots
    while (result.length < count && availableItems.length > 0) {
      // Check duplicate policy
      if ("${duplicatePolicy}" === "forbid" && drawnIds.size >= availableItems.length) {
        print(\`[Rune Weaver] ${className}: Cannot draw more unique items (duplicatePolicy="forbid")\`);
        break;
      }

      const currentTotalWeight = availableItems.reduce((sum, item) => sum + item.weight, 0);
      if (currentTotalWeight <= 0) {
        print(\`[Rune Weaver] ${className}: No weight available in pool\`);
        break;
      }

      let random = RandomFloat(0, currentTotalWeight);
      let drawnItem: WeightedItem<T> | null = null;

      for (const item of availableItems) {
        random -= item.weight;
        if (random <= 0) {
          drawnItem = item;
          break;
        }
      }

      if (drawnItem) {
        const itemId = (drawnItem.item as any).id;

        // Check for duplicates if policy is "forbid"
        if ("${duplicatePolicy}" === "forbid" && drawnIds.has(itemId)) {
          // Remove this item and try again
          const index = availableItems.indexOf(drawnItem);
          if (index > -1) {
            availableItems.splice(index, 1);
          }
          continue;
        }

        result.push(drawnItem.item);
        drawnIds.add(itemId);

        // Remove from available items
        const index = availableItems.indexOf(drawnItem);
        if (index > -1) {
          availableItems.splice(index, 1);
        }
      } else {
        break;
      }
    }

${hasSessionState ? `    // Update currentChoiceIds in session state
    this.sessionState.currentChoiceIds = result.map(item => (item as any).id);` : ""}

    return result;
  }
`
    : ";
